title:
次のファイングレイン監査(FGA)ポリシーがHR.EMPLOYEES表に対して作成されています。

BEGIN
  DBMS_FGA.ADD_POLICY(
    object_schema   => 'HR',
    object_name     => 'EMPLOYEES',
    policy_name     => 'FGA_SALARY_AUDIT',
    audit_condition => 'DEPARTMENT_ID = 10',
    audit_column    => 'SALARY, COMMISSION_PCT',
    enable          => TRUE,
    statement_types => 'SELECT',
    audit_column_opts => DBMS_FGA.ALL_COLUMNS
  );
END;
/

このポリシーが有効な状態で、次のSQL文のうち監査レコードが生成されるものを選択してください。なお、HR.EMPLOYEES表にはDEPARTMENT_ID = 10のデータが存在するものとします(2つ選択してください)。

SQL文A: SELECT employee_id, salary, commission_pct FROM hr.employees WHERE department_id = 10;
SQL文B: SELECT employee_id, salary FROM hr.employees WHERE department_id = 10;
SQL文C: SELECT employee_id, salary, commission_pct FROM hr.employees WHERE department_id = 20;
SQL文D: SELECT employee_id, commission_pct FROM hr.employees WHERE department_id = 10;
SQL文E: SELECT employee_id, salary, commission_pct FROM hr.employees;
